import { PATIENT_PROFILE } from './patientProfile';

/**
 * Today's reminders for list view: derived from patient profile schedules.
 * Interactive reminder text is no longer pre-done—it's generated by the AI (see API /api/generate-reminder).
 */
export function getTodaysReminders() {
  const now = new Date();
  const hour = now.getHours();
  const schedules = PATIENT_PROFILE.schedules || [];
  return schedules
    .filter((s) => s.type !== 'medication' || s.id === 'med-morning' || s.id === 'med-evening')
    .slice(0, 6)
    .map((s) => ({
      id: s.id ? `rem-${s.id}` : `rem-${s.type}`,
      title: s.title,
      time: s.time,
      completed:
        (s.type === 'water' && hour >= 12) ||
        (s.type === 'walking' && hour >= 10) ||
        (s.type === 'legs' && hour >= 14),
    }));
}
